#!/usr/bin/env bash
# sign-action-url.sh: generate an HMAC-signed notify-hook URL. Used by the
# watchdog and orchestrator to embed action buttons in ntfy pushes; usable
# stand-alone for testing.
#
# Reads the secret from $NOTIFY_HOOK_SECRET or ~/.claude/notify-hook.secret
# (auto-generated by notify-hook.py on first start). Output is the full URL.
#
# Usage:
#   bin/sign-action-url.sh <action> <run-id> [<text>] [--ttl <seconds>]
#                                                     [--base <url>]
#
#   action:   approve | pause | resume | stop | priority
#   run-id:   target run
#   text:     optional, URL-encoded into ?text=
#   --ttl:    URL validity in seconds (default 1800 = 30 min)
#   --base:   hook base, default $NOTIFY_HOOK_BASE or http://127.0.0.1:8421
#
# Example:
#   bin/sign-action-url.sh approve r12345
#   bin/sign-action-url.sh priority r12345 'drop unit-X' --ttl 3600

set -euo pipefail
action="${1:?usage: sign-action-url.sh <action> <run-id> [<text>] [--ttl N] [--base URL]}"
rid="${2:?need run-id}"
shift 2
text=""
ttl=1800
base="${NOTIFY_HOOK_BASE:-http://127.0.0.1:8421}"
while [ $# -gt 0 ]; do case "$1" in
  --ttl) ttl="$2"; shift 2 ;;
  --base) base="$2"; shift 2 ;;
  *) text="$1"; shift ;;
esac done

secret_file="${NOTIFY_HOOK_SECRET_FILE:-$HOME/.claude/notify-hook.secret}"
if [ -n "${NOTIFY_HOOK_SECRET:-}" ]; then secret="$NOTIFY_HOOK_SECRET"
elif [ -r "$secret_file" ]; then secret="$(cat "$secret_file")"
else echo "no secret (run bin/notify-hook.py once to generate $secret_file)" >&2; exit 2
fi

exp=$(( $(date +%s) + ttl ))
path="/$action/$rid"
sig=$(printf 'GET\n%s\n%s' "$path" "$exp" | openssl dgst -sha256 -hmac "$secret" -hex 2>/dev/null | awk '{print $NF}')

if [ -n "$text" ]; then
  # urlencode the text (RFC3986 minimal): use jq for portable encoding
  enc="$(printf '%s' "$text" | jq -sRr @uri)"
  echo "${base}${path}?sig=${sig}&exp=${exp}&text=${enc}"
else
  echo "${base}${path}?sig=${sig}&exp=${exp}"
fi
